import { useMemo, type KeyboardEvent } from 'react';
import { Alert, Button, Icon, Select, Skeleton } from '@acme/ui';
import styles from './TransactionTable.module.css';

export type TransactionStatus = 'pending' | 'completed' | 'failed' | 'refunded';

export type SortColumn = 'date' | 'amount' | 'status' | 'merchant' | 'paymentMethod';
export type SortDirection = 'ascending' | 'descending' | 'none';

export interface Transaction {
  id: string;
  date: string;
  amount: number;
  status: TransactionStatus;
  merchant: string;
  paymentMethod: string;
}

export interface TransactionTableProps {
  transactions: Transaction[];
  sortColumn?: SortColumn | null;
  sortDirection?: SortDirection;
  onSortChange?: (column: string, direction: 'ascending' | 'descending') => void;
  page: number;
  pageSize: 25 | 50 | 100;
  totalCount: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: 25 | 50 | 100) => void;
  onRowClick?: (transactionId: string) => void;
  state: 'idle' | 'loading' | 'empty' | 'error';
  errorMessage?: string;
  isRowNavigating?: boolean;
}

const COLUMNS: { key: SortColumn; label: string }[] = [
  { key: 'date', label: 'Date' },
  { key: 'amount', label: 'Amount' },
  { key: 'status', label: 'Status' },
  { key: 'merchant', label: 'Merchant' },
  { key: 'paymentMethod', label: 'Payment method' },
];

const STATUS_LABEL: Record<TransactionStatus, string> = {
  pending: 'Pending',
  completed: 'Completed',
  failed: 'Failed',
  refunded: 'Refunded',
};

const PAGE_SIZE_OPTIONS = [
  { label: '25', value: '25' },
  { label: '50', value: '50' },
  { label: '100', value: '100' },
];

function formatAmount(amount: number): string {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(amount);
}

function formatDateShort(iso: string): string {
  return new Intl.DateTimeFormat('en-US', { month: 'short', day: 'numeric', year: 'numeric' }).format(
    new Date(iso),
  );
}

function formatDateFull(iso: string): string {
  return new Intl.DateTimeFormat('en-US', {
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    year: 'numeric',
  }).format(new Date(iso));
}

function nextSortDirection(
  column: SortColumn,
  sortColumn?: SortColumn | null,
  sortDirection?: SortDirection,
): 'ascending' | 'descending' {
  if (sortColumn === column && sortDirection === 'ascending') {
    return 'descending';
  }
  return 'ascending';
}

function sortButtonLabel(label: string, isActive: boolean, sortDirection?: SortDirection): string {
  if (!isActive || sortDirection === 'none' || sortDirection === undefined) {
    return `${label}, not sorted, activate to sort ascending`;
  }
  const nextDirection = sortDirection === 'ascending' ? 'descending' : 'ascending';
  return `${label}, sorted ${sortDirection}, activate to sort ${nextDirection}`;
}

function StatusChip({ status }: { status: TransactionStatus }) {
  const chipClass = {
    pending: styles.chipPending,
    completed: styles.chipCompleted,
    failed: styles.chipFailed,
    refunded: styles.chipRefunded,
  }[status];

  return <span className={`${styles.chip} ${chipClass}`}>{STATUS_LABEL[status]}</span>;
}

/**
 * Displays a fintech user's transaction history with sorting, pagination and
 * row-level navigation, covering idle/loading/empty/error states plus per-row
 * status badges.
 */
export function TransactionTable({
  transactions,
  sortColumn = null,
  sortDirection = 'none',
  onSortChange,
  page,
  pageSize,
  totalCount,
  onPageChange,
  onPageSizeChange,
  onRowClick,
  state,
  errorMessage,
  isRowNavigating = false,
}: TransactionTableProps) {
  // "empty" is reachable either via the explicit `state === 'empty'` prop value
  // or via `state === 'idle'` with a zero-length `transactions` array, per spec.
  const isEmpty = state === 'empty' || (state === 'idle' && transactions.length === 0);
  const isDefault = state === 'idle' && transactions.length > 0;
  const isSorted = sortColumn !== null && sortDirection !== 'none';
  const isPaginated = totalCount > pageSize;
  const isRowClickable = typeof onRowClick === 'function';

  const totalPages = Math.max(1, Math.ceil(totalCount / pageSize));
  const isFirstPage = page <= 1;
  const isLastPage = page >= totalPages;

  const rangeStart = totalCount === 0 ? 0 : (page - 1) * pageSize + 1;
  const rangeEnd = Math.min(page * pageSize, totalCount);

  const liveMessage = useMemo(() => {
    if (state === 'loading') {
      return 'Loading transactions';
    }
    if (isSorted && sortColumn) {
      return `Sorted by ${sortColumn} ${sortDirection}`;
    }
    if (isPaginated) {
      return `Showing rows ${rangeStart}-${rangeEnd} of ${totalCount}`;
    }
    return '';
  }, [state, isSorted, sortColumn, sortDirection, isPaginated, rangeStart, rangeEnd, totalCount]);

  const handleSortClick = (column: SortColumn) => {
    if (!onSortChange) {
      return;
    }
    onSortChange(column, nextSortDirection(column, sortColumn, sortDirection));
  };

  const handleRowKeyDown = (event: KeyboardEvent<HTMLTableRowElement>, transactionId: string) => {
    if (!isRowClickable || isRowNavigating) {
      return;
    }
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      onRowClick?.(transactionId);
    }
  };

  const rowAccessibleName = (transaction: Transaction) =>
    `Transaction on ${formatDateFull(transaction.date)}, ${formatAmount(transaction.amount)}, ${
      STATUS_LABEL[transaction.status]
    }, view details`;

  if (state === 'error') {
    return (
      <div className={styles.root}>
        <div className={styles.errorWrapper}>
          <Alert tone="error" role="alert" title="Unable to load transactions">
            {errorMessage ?? 'Something went wrong while loading transactions.'}
          </Alert>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.root}>
      <div className={styles.statusRegion} role="status" aria-live="polite">
        {liveMessage}
      </div>
      <div className={styles.tableScroll}>
        <table className={styles.table}>
          <caption className={styles.visuallyHidden}>Transactions</caption>
          <thead>
            <tr>
              {COLUMNS.map((column) => {
                const isActiveColumn = sortColumn === column.key;
                const ariaSort = isActiveColumn && sortDirection !== 'none' ? sortDirection : 'none';
                return (
                  <th key={column.key} scope="col" aria-sort={ariaSort}>
                    {onSortChange ? (
                      <button
                        type="button"
                        className={styles.sortButton}
                        onClick={() => handleSortClick(column.key)}
                        aria-label={sortButtonLabel(column.label, isActiveColumn, sortDirection)}
                      >
                        <span aria-hidden="true">{column.label}</span>
                        {isActiveColumn && sortDirection !== 'none' && (
                          <Icon
                            name={sortDirection === 'ascending' ? 'arrow-up' : 'arrow-down'}
                            size={14}
                            aria-hidden
                          />
                        )}
                      </button>
                    ) : (
                      column.label
                    )}
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {state === 'loading' &&
              Array.from({ length: 5 }).map((_, rowIndex) => (
                <tr key={`skeleton-row-${rowIndex}`}>
                  {COLUMNS.map((column) => (
                    <td key={column.key}>
                      <Skeleton width="100%" height="16px" radius="sm" />
                    </td>
                  ))}
                </tr>
              ))}

            {isEmpty && (
              <tr>
                <td className={styles.emptyCell} colSpan={COLUMNS.length}>
                  No transactions match your filters
                </td>
              </tr>
            )}

            {isDefault &&
              transactions.map((transaction) => (
                <tr
                  key={transaction.id}
                  className={isRowClickable ? styles.rowClickable : undefined}
                  role={isRowClickable ? 'button' : undefined}
                  tabIndex={isRowClickable ? 0 : undefined}
                  aria-disabled={isRowClickable && isRowNavigating ? 'true' : undefined}
                  aria-label={isRowClickable ? rowAccessibleName(transaction) : undefined}
                  onClick={
                    isRowClickable && !isRowNavigating ? () => onRowClick?.(transaction.id) : undefined
                  }
                  onKeyDown={
                    isRowClickable ? (event) => handleRowKeyDown(event, transaction.id) : undefined
                  }
                >
                  <td>
                    <span aria-hidden="true">{formatDateShort(transaction.date)}</span>
                    <span className={styles.visuallyHidden}>{formatDateFull(transaction.date)}</span>
                  </td>
                  <td>
                    <span aria-hidden="true">{formatAmount(transaction.amount)}</span>
                    <span className={styles.visuallyHidden}>
                      {transaction.amount.toFixed(2)} US dollars
                    </span>
                  </td>
                  <td>
                    <StatusChip status={transaction.status} />
                  </td>
                  <td>{transaction.merchant}</td>
                  <td>{transaction.paymentMethod}</td>
                </tr>
              ))}
          </tbody>
        </table>
      </div>

      {isPaginated && (
        <nav className={styles.pagination} aria-label="Pagination">
          <Button
            variant="ghost"
            size="sm"
            disabled={isFirstPage}
            onClick={() => onPageChange(page - 1)}
            aria-label="Previous page"
          >
            <Icon name="chevron-left" size={16} aria-hidden />
          </Button>
          <span aria-current="page" className={styles.pageIndicator}>
            Page {page} of {totalPages}
          </span>
          <Button
            variant="ghost"
            size="sm"
            disabled={isLastPage}
            onClick={() => onPageChange(page + 1)}
            aria-label="Next page"
          >
            <Icon name="chevron-right" size={16} aria-hidden />
          </Button>
          <label className={styles.pageSizeLabel} htmlFor="transaction-table-page-size">
            Rows per page
          </label>
          <Select
            options={PAGE_SIZE_OPTIONS}
            value={String(pageSize)}
            onChange={(value: string) => onPageSizeChange(Number(value) as 25 | 50 | 100)}
            id="transaction-table-page-size"
          />
        </nav>
      )}
    </div>
  );
}

.root {
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  font-family: var(--font-family-sans);
}

.visuallyHidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.statusRegion {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.errorWrapper {
  padding: var(--space-4);
  border-radius: var(--radius-md);
  background-color: var(--color-feedback-error-subtle);
}

.tableScroll {
  overflow-x: auto;
  border-radius: var(--radius-sm);
  border: 1px solid var(--color-border-default);
  background-color: var(--color-surface-card);
}

@media (max-width: 768px) {
  .tableScroll {
    overflow-x: auto;
  }
}

.table {
  width: 100%;
  border-collapse: collapse;
  font-size: var(--font-size-sm);
  line-height: var(--font-line-height-normal);
  color: var(--color-text-primary);
}

.table th,
.table td {
  padding: var(--space-3) var(--space-4);
  text-align: left;
  border-bottom: 1px solid var(--color-border-default);
  font-weight: var(--font-weight-regular);
}

.table th {
  color: var(--color-text-secondary);
  font-weight: var(--font-weight-medium);
}

.sortButton {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  background: none;
  border: none;
  cursor: pointer;
  font: inherit;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
  padding: var(--space-1);
  border-radius: var(--radius-sm);
}

.sortButton:focus-visible {
  outline: 2px solid var(--color-focus-ring);
  outline-offset: 2px;
}

.rowClickable {
  cursor: pointer;
}

.rowClickable:hover,
.rowClickable:focus-visible {
  background-color: var(--color-background-subtle);
}

.rowClickable:focus-visible {
  outline: 2px solid var(--color-focus-ring);
  outline-offset: -2px;
}

.rowClickable[aria-disabled='true'] {
  cursor: default;
  color: var(--color-text-disabled);
}

.emptyCell {
  text-align: center;
  color: var(--color-text-secondary);
  font-size: var(--font-size-sm);
  padding: var(--space-6);
}

.chip {
  display: inline-flex;
  align-items: center;
  padding: var(--space-1) var(--space-2);
  border-radius: var(--radius-full);
  border: 1px solid var(--color-border-default);
  background-color: var(--color-background-subtle);
  font-size: var(--font-size-xs);
  font-weight: var(--font-weight-medium);
}

.chipPending {
  color: var(--color-feedback-warning);
}

.chipCompleted {
  color: var(--color-feedback-success);
}

.chipFailed {
  color: var(--color-feedback-error);
}

.chipRefunded {
  color: var(--color-text-secondary);
}

.pagination {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-4);
}

.pageIndicator {
  color: var(--color-action-primary-default);
  font-size: var(--font-size-sm);
  border: 1px solid var(--color-border-strong);
  border-radius: var(--radius-sm);
  padding: var(--space-1) var(--space-2);
}

.pageIndicator[aria-disabled='true'] {
  color: var(--color-action-primary-disabled);
}

.pageSizeLabel {
  margin-left: auto;
  color: var(--color-text-secondary);
  font-size: var(--font-size-sm);
}

@media (prefers-reduced-motion: reduce) {
  .root * {
    animation: none !important;
    transition: none !important;
  }
}

import type { Meta, StoryObj } from '@storybook/react';
import { TransactionTable, type Transaction } from './TransactionTable';

const meta: Meta<typeof TransactionTable> = {
  title: 'Components/TransactionTable',
  component: TransactionTable,
};

export default meta;
type Story = StoryObj<typeof TransactionTable>;

const baseTransactions: Transaction[] = [
  {
    id: 'txn_1',
    date: '2026-06-01',
    amount: 42.5,
    status: 'completed',
    merchant: 'Coffee Roasters',
    paymentMethod: 'Visa •••• 4242',
  },
  {
    id: 'txn_2',
    date: '2026-06-03',
    amount: 129.99,
    status: 'pending',
    merchant: 'Cloud Hosting Co',
    paymentMethod: 'Mastercard •••• 1881',
  },
  {
    id: 'txn_3',
    date: '2026-06-05',
    amount: 15.0,
    status: 'failed',
    merchant: 'Streaming Plus',
    paymentMethod: 'Visa •••• 4242',
  },
  {
    id: 'txn_4',
    date: '2026-06-06',
    amount: 60.0,
    status: 'refunded',
    merchant: 'Office Supplies Inc',
    paymentMethod: 'Amex •••• 1005',
  },
];

const noop = () => {};

export const Default: Story = {
  args: {
    transactions: baseTransactions,
    page: 1,
    pageSize: 25,
    totalCount: baseTransactions.length,
    onPageChange: noop,
    onPageSizeChange: noop,
    state: 'idle',
  },
};

export const Sorted: Story = {
  args: {
    ...Default.args,
    sortColumn: 'amount',
    sortDirection: 'ascending',
    onSortChange: noop,
  },
};

export const Paginated: Story = {
  args: {
    ...Default.args,
    page: 2,
    pageSize: 25,
    totalCount: 120,
  },
};

export const StatusPending: Story = {
  name: 'status:pending',
  args: {
    ...Default.args,
    transactions: [baseTransactions[1]],
    totalCount: 1,
  },
};

export const StatusCompleted: Story = {
  name: 'status:completed',
  args: {
    ...Default.args,
    transactions: [baseTransactions[0]],
    totalCount: 1,
  },
};

export const StatusFailed: Story = {
  name: 'status:failed',
  args: {
    ...Default.args,
    transactions: [baseTransactions[2]],
    totalCount: 1,
  },
};

export const StatusRefunded: Story = {
  name: 'status:refunded',
  args: {
    ...Default.args,
    transactions: [baseTransactions[3]],
    totalCount: 1,
  },
};

export const RowClickable: Story = {
  name: 'row-clickable',
  args: {
    ...Default.args,
    onRowClick: noop,
  },
};

export const Loading: Story = {
  args: {
    ...Default.args,
    transactions: [],
    state: 'loading',
  },
};

export const Empty: Story = {
  args: {
    ...Default.args,
    transactions: [],
    totalCount: 0,
    state: 'empty',
  },
};

export const ErrorState: Story = {
  name: 'error',
  args: {
    ...Default.args,
    transactions: [],
    state: 'error',
    errorMessage: 'We could not load your transactions. Please try again.',
  },
};

import { describe, expect, it, vi } from 'vitest';
import { render, screen, within } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { axe, toHaveNoViolations } from 'jest-axe';
import { TransactionTable, type Transaction } from './TransactionTable';

expect.extend(toHaveNoViolations);

const transactions: Transaction[] = [
  {
    id: 'txn_1',
    date: '2026-06-01',
    amount: 42.5,
    status: 'completed',
    merchant: 'Coffee Roasters',
    paymentMethod: 'Visa •••• 4242',
  },
  {
    id: 'txn_2',
    date: '2026-06-03',
    amount: 129.99,
    status: 'pending',
    merchant: 'Cloud Hosting Co',
    paymentMethod: 'Mastercard •••• 1881',
  },
  {
    id: 'txn_3',
    date: '2026-06-05',
    amount: 15.0,
    status: 'failed',
    merchant: 'Streaming Plus',
    paymentMethod: 'Visa •••• 4242',
  },
  {
    id: 'txn_4',
    date: '2026-06-06',
    amount: 60.0,
    status: 'refunded',
    merchant: 'Office Supplies Inc',
    paymentMethod: 'Amex •••• 1005',
  },
];

const noop = () => {};

const baseProps = {
  page: 1,
  pageSize: 25 as const,
  totalCount: transactions.length,
  onPageChange: noop,
  onPageSizeChange: noop,
};

describe('TransactionTable', () => {
  it('renders the default state as a native table with rows', () => {
    render(<TransactionTable {...baseProps} transactions={transactions} state="idle" />);

    const table = screen.getByRole('table', { name: 'Transactions' });
    expect(table).toBeInTheDocument();
    expect(screen.getAllByRole('columnheader')).toHaveLength(5);
    expect(screen.getByText('Coffee Roasters')).toBeInTheDocument();
  });

  it('renders the sorted state with aria-sort and an accessible sort button', () => {
    render(
      <TransactionTable
        {...baseProps}
        transactions={transactions}
        state="idle"
        sortColumn="amount"
        sortDirection="ascending"
        onSortChange={noop}
      />,
    );

    const amountHeader = screen.getByRole('columnheader', { name: /amount/i });
    expect(amountHeader).toHaveAttribute('aria-sort', 'ascending');
    expect(
      screen.getByRole('button', { name: /amount, sorted ascending, activate to sort descending/i }),
    ).toBeInTheDocument();
  });

  it('renders the paginated state with a Pagination nav and disables bounds correctly', () => {
    render(
      <TransactionTable
        {...baseProps}
        transactions={transactions}
        state="idle"
        page={2}
        pageSize={25}
        totalCount={120}
      />,
    );

    const nav = screen.getByRole('navigation', { name: 'Pagination' });
    expect(within(nav).getByRole('button', { name: 'Previous page' })).toBeEnabled();
    expect(within(nav).getByRole('button', { name: 'Next page' })).toBeEnabled();
    expect(within(nav).getByText('Page 2 of 5')).toBeInTheDocument();
  });

  it('renders the status:pending chip with text label', () => {
    render(
      <TransactionTable {...baseProps} transactions={[transactions[1]]} totalCount={1} state="idle" />,
    );
    expect(screen.getByText('Pending')).toBeInTheDocument();
  });

  it('renders the status:completed chip with text label', () => {
    render(
      <TransactionTable {...baseProps} transactions={[transactions[0]]} totalCount={1} state="idle" />,
    );
    expect(screen.getByText('Completed')).toBeInTheDocument();
  });

  it('renders the status:failed chip with text label', () => {
    render(
      <TransactionTable {...baseProps} transactions={[transactions[2]]} totalCount={1} state="idle" />,
    );
    expect(screen.getByText('Failed')).toBeInTheDocument();
  });

  it('renders the status:refunded chip with text label', () => {
    render(
      <TransactionTable {...baseProps} transactions={[transactions[3]]} totalCount={1} state="idle" />,
    );
    expect(screen.getByText('Refunded')).toBeInTheDocument();
  });

  it('renders row-clickable rows that are keyboard operable', async () => {
    const user = userEvent.setup();
    const handleRowClick = vi.fn();
    render(
      <TransactionTable
        {...baseProps}
        transactions={transactions}
        state="idle"
        onRowClick={handleRowClick}
      />,
    );

    const row = screen.getByRole('button', { name: /transaction on .*coffee.*|transaction on .*completed.*/i });
    row.focus();
    await user.keyboard('{Enter}');
    expect(handleRowClick).toHaveBeenCalledWith('txn_1');
  });

  it('renders the loading state with skeleton rows and an announced status', () => {
    render(<TransactionTable {...baseProps} transactions={[]} state="loading" />);
    expect(screen.getByRole('status')).toHaveTextContent('Loading transactions');
  });

  it('renders the empty state with a plain-text message and no error styling', () => {
    render(<TransactionTable {...baseProps} transactions={[]} totalCount={0} state="empty" />);
    expect(screen.getByText('No transactions match your filters')).toBeInTheDocument();
    expect(screen.queryByRole('alert')).not.toBeInTheDocument();
  });

  it('renders the error state using the Alert primitive with role="alert"', () => {
    render(
      <TransactionTable
        {...baseProps}
        transactions={[]}
        state="error"
        errorMessage="Could not load transactions."
      />,
    );
    expect(screen.getByRole('alert')).toHaveTextContent('Could not load transactions.');
  });

  it('has no detectable accessibility violations (axe smoke test)', async () => {
    const { container } = render(
      <TransactionTable {...baseProps} transactions={transactions} state="idle" onRowClick={noop} />,
    );
    expect(await axe(container)).toHaveNoViolations();
  });
});

import { TransactionTable } from './TransactionTable';

export { TransactionTable };
export type {
  TransactionTableProps,
  Transaction,
  TransactionStatus,
  SortColumn,
  SortDirection,
} from './TransactionTable';

export default TransactionTable;
